module freq_div
(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);
    reg [1:0] cnt_50;
    reg [3:0] cnt_100;
    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_50 <= 2'b00;
            CLK_50 <= 1'b0;
        end else if (cnt_50 == 2'b10) begin
            CLK_50 <= ~CLK_50;
            cnt_50 <= 2'b00;
        end else begin
            cnt_50 <= cnt_50 + 1;
        end
    end
    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_10 <= 4'b0000;
            CLK_10 <= 1'b0;
        end else if (cnt_10 == 4'b0100) begin
            CLK_10 <= ~CLK_10;
            cnt_10 <= 4'b0000;
        end else begin
            cnt_10 <= cnt_10 + 1;
        end
    end
    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_100 <= 6'b000000;
            CLK_1 <= 1'b0;
        end else if (cnt_100 == 6'b001100) begin
            CLK_1 <= ~CLK_1;
            cnt_100 <= 6'b000000;
        end else begin
            cnt_100 <= cnt_100 + 1;
        end
    end
endmodule
